package com.hfad.agencyapp.data;

import android.content.ContentValues;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;

import com.hfad.agencyapp.ui.models.Customer;

import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

/**
 * Simple SQLiteOpenHelper for customers table. Uses TEXT id (UUID) to keep compatibility.
 */
public class CustomerDbHelper extends SQLiteOpenHelper {
    private static final String DATABASE_NAME = "agency_app.db";
    private static final int DATABASE_VERSION = 1;

    public static final String TABLE_CUSTOMERS = "customers";
    public static final String COL_ID = "id";
    public static final String COL_BUSINESS = "business_name";
    public static final String COL_CONTACT = "contact_person";
    public static final String COL_PHONE = "phone";
    public static final String COL_ADDRESS = "address";
    public static final String COL_CITY = "city";

    public CustomerDbHelper(Context context) {
        super(context, DATABASE_NAME, null, DATABASE_VERSION);
    }

    @Override
    public void onCreate(SQLiteDatabase db) {
        String sql = "CREATE TABLE " + TABLE_CUSTOMERS + " ("
                + COL_ID + " TEXT PRIMARY KEY,"
                + COL_BUSINESS + " TEXT,"
                + COL_CONTACT + " TEXT,"
                + COL_PHONE + " TEXT,"
                + COL_ADDRESS + " TEXT,"
                + COL_CITY + " TEXT"
                + ");";
        db.execSQL(sql);
    }

    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_CUSTOMERS);
        onCreate(db);
    }

    // Insert or update
    public String insertCustomer(Customer c) {
        SQLiteDatabase db = getWritableDatabase();
        if (c.getId() == null || c.getId().isEmpty()) {
            c.setId(UUID.randomUUID().toString());
        }
        ContentValues cv = new ContentValues();
        cv.put(COL_ID, c.getId());
        cv.put(COL_BUSINESS, c.getBusinessName());
        cv.put(COL_CONTACT, c.getContactPerson());
        cv.put(COL_PHONE, c.getPhoneNumber());
        cv.put(COL_ADDRESS, c.getAddress());
        cv.put(COL_CITY, c.getCity());

        long res = db.insertWithOnConflict(TABLE_CUSTOMERS, null, cv, SQLiteDatabase.CONFLICT_REPLACE);
        return res == -1 ? null : c.getId();
    }

    public boolean deleteCustomer(String id) {
        SQLiteDatabase db = getWritableDatabase();
        int rows = db.delete(TABLE_CUSTOMERS, COL_ID + " = ?", new String[]{id});
        return rows > 0;
    }

    public List<Customer> getAllCustomers() {
        List<Customer> list = new ArrayList<>();
        SQLiteDatabase db = getReadableDatabase();
        Cursor cursor = db.query(TABLE_CUSTOMERS, null, null, null, null, null, COL_BUSINESS + " ASC");
        if (cursor != null) {
            while (cursor.moveToNext()) {
                Customer c = cursorToCustomer(cursor);
                list.add(c);
            }
            cursor.close();
        }
        return list;
    }

    public Customer getCustomerById(String id) {
        SQLiteDatabase db = getReadableDatabase();
        Cursor cursor = db.query(TABLE_CUSTOMERS, null, COL_ID + " = ?", new String[]{id}, null, null, null);
        if (cursor != null) {
            if (cursor.moveToFirst()) {
                Customer c = cursorToCustomer(cursor);
                cursor.close();
                return c;
            }
            cursor.close();
        }
        return null;
    }

    public List<Customer> searchCustomers(String query) {
        List<Customer> list = new ArrayList<>();
        SQLiteDatabase db = getReadableDatabase();
        String q = "%" + query + "%";
        Cursor cursor = db.query(TABLE_CUSTOMERS, null, COL_BUSINESS + " LIKE ? OR " + COL_CONTACT + " LIKE ? OR " + COL_CITY + " LIKE ?",
                new String[]{q, q, q}, null, null, COL_BUSINESS + " ASC");
        if (cursor != null) {
            while (cursor.moveToNext()) {
                list.add(cursorToCustomer(cursor));
            }
            cursor.close();
        }
        return list;
    }

    private Customer cursorToCustomer(Cursor cursor) {
        String id = cursor.getString(cursor.getColumnIndexOrThrow(COL_ID));
        String business = cursor.getString(cursor.getColumnIndexOrThrow(COL_BUSINESS));
        String contact = cursor.getString(cursor.getColumnIndexOrThrow(COL_CONTACT));
        String phone = cursor.getString(cursor.getColumnIndexOrThrow(COL_PHONE));
        String address = cursor.getString(cursor.getColumnIndexOrThrow(COL_ADDRESS));
        String city = cursor.getString(cursor.getColumnIndexOrThrow(COL_CITY));
        return new Customer(id, business, contact, phone, address, city);
    }
}

package com.hfad.agencyapp.data;

import android.content.Context;

import com.hfad.agencyapp.ui.models.Customer;

import java.util.List;
import java.util.concurrent.Callable;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;

/**
 * Repository that abstracts DB operations and runs them off the main thread.
 */
public class CustomerRepository {
    private final CustomerDbHelper dbHelper;
    private final ExecutorService executor = Executors.newSingleThreadExecutor();

    public CustomerRepository(Context context) {
        dbHelper = new CustomerDbHelper(context.getApplicationContext());
    }

    public Future<List<Customer>> getAllCustomersAsync() {
        return executor.submit(new Callable<List<Customer>>() {
            @Override
            public List<Customer> call() {
                return dbHelper.getAllCustomers();
            }
        });
    }

    public Future<List<Customer>> searchCustomersAsync(final String q) {
        return executor.submit(() -> dbHelper.searchCustomers(q));
    }

    public Future<String> insertOrUpdateAsync(final Customer c) {
        return executor.submit(() -> dbHelper.insertCustomer(c));
    }

    public Future<Boolean> deleteCustomerAsync(final String id) {
        return executor.submit(() -> dbHelper.deleteCustomer(id));
    }

    public Future<Customer> getByIdAsync(final String id) {
        return executor.submit(() -> dbHelper.getCustomerById(id));
    }
}

package com.hfad.agencyapp.ui.adapters;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.DiffUtil;
import androidx.recyclerview.widget.ListAdapter;
import androidx.recyclerview.widget.RecyclerView;

import com.hfad.agencyapp.databinding.ItemCustomerBinding;
import com.hfad.agencyapp.ui.models.Customer;

/**
 * Adapter for customer list using ListAdapter + DiffUtil and ViewBinding.
 */
public class CustomersAdapter extends ListAdapter<Customer, CustomersAdapter.CustomerViewHolder> {

    public interface OnCustomerActionListener {
        void onClick(Customer customer);
        void onLongClick(Customer customer, View anchor);
    }

    private final OnCustomerActionListener listener;

    public CustomersAdapter(OnCustomerActionListener listener) {
        super(new DiffUtil.ItemCallback<Customer>() {
            @Override
            public boolean areItemsTheSame(@NonNull Customer oldItem, @NonNull Customer newItem) {
                return oldItem.getId() != null && oldItem.getId().equals(newItem.getId());
            }

            @Override
            public boolean areContentsTheSame(@NonNull Customer oldItem, @NonNull Customer newItem) {
                return oldItem.getBusinessName().equals(newItem.getBusinessName())
                        && oldItem.getContactPerson().equals(newItem.getContactPerson())
                        && oldItem.getCity().equals(newItem.getCity());
            }
        });
        this.listener = listener;
    }

    @NonNull
    @Override
    public CustomerViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        ItemCustomerBinding binding = ItemCustomerBinding.inflate(LayoutInflater.from(parent.getContext()), parent, false);
        return new CustomerViewHolder(binding);
    }

    @Override
    public void onBindViewHolder(@NonNull CustomerViewHolder holder, int position) {
        Customer c = getItem(position);
        holder.bind(c, listener);
    }

    static class CustomerViewHolder extends RecyclerView.ViewHolder {
        private final ItemCustomerBinding binding;

        CustomerViewHolder(ItemCustomerBinding binding) {
            super(binding.getRoot());
            this.binding = binding;
        }

        void bind(Customer c, OnCustomerActionListener listener) {
            binding.tvBusinessName.setText(c.getBusinessName());
            binding.tvContactPerson.setText(c.getContactPerson());
            binding.tvCity.setText(c.getCity());

            // Outstanding placeholder: 0.00
            binding.tvOutstandingLabel.setText("Outstanding");
            binding.tvOutstandingAmount.setText("Rs. 0.00");

            binding.getRoot().setOnClickListener(v -> listener.onClick(c));
            binding.getRoot().setOnLongClickListener(v -> {
                listener.onLongClick(c, v);
                return true;
            });
        }
    }
}

package com.hfad.agencyapp.ui.customers;

import android.os.Bundle;
import android.text.TextUtils;
import android.view.Menu;
import android.view.MenuItem;
import android.widget.Toast;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;

import com.google.android.material.snackbar.Snackbar;
import com.hfad.agencyapp.R;
import com.hfad.agencyapp.databinding.ActivityAddEditCustomerBinding;
import com.hfad.agencyapp.ui.models.Customer;
import com.hfad.agencyapp.viewmodel.CustomerViewModel;

/**
 * Activity for adding or editing a customer.
 */
public class AddEditCustomerActivity extends AppCompatActivity {
    private ActivityAddEditCustomerBinding binding;
    private CustomerViewModel viewModel;
    private String customerId;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityAddEditCustomerBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        setSupportActionBar(binding.toolbar);
        getSupportActionBar().setDisplayHomeAsUpEnabled(true);
        binding.toolbar.setNavigationOnClickListener(v -> onBackPressed());

        viewModel = new ViewModelProvider(this).get(CustomerViewModel.class);

        customerId = getIntent().getStringExtra("customer_id");
        if (customerId != null) {
            getSupportActionBar().setTitle("Edit Customer");
            loadCustomer(customerId);
        } else {
            getSupportActionBar().setTitle("Add Customer");
        }
    }

    private void loadCustomer(String id) {
        Customer c = viewModel.getById(id);
        if (c != null) {
            binding.etBusinessName.setText(c.getBusinessName());
            binding.etContactPerson.setText(c.getContactPerson());
            binding.etPhone.setText(c.getPhoneNumber());
            binding.etCity.setText(c.getCity());
            binding.etAddress.setText(c.getAddress());
        }
    }

    @Override
    public boolean onCreateOptionsMenu(Menu menu) {
        getMenuInflater().inflate(R.menu.menu_add_edit, menu);
        return true;
    }

    @Override
    public boolean onOptionsItemSelected(MenuItem item) {
        if (item.getItemId() == R.id.action_save) {
            saveCustomer();
            return true;
        }
        return super.onOptionsItemSelected(item);
    }

    private void saveCustomer() {
        String business = binding.etBusinessName.getText().toString().trim();
        String contact = binding.etContactPerson.getText().toString().trim();
        String phone = binding.etPhone.getText().toString().trim();
        String city = binding.etCity.getText().toString().trim();
        String address = binding.etAddress.getText().toString().trim();

        boolean valid = true;
        if (TextUtils.isEmpty(business)) {
            binding.tilBusinessName.setError("Business name required");
            valid = false;
        } else {
            binding.tilBusinessName.setError(null);
        }
        if (TextUtils.isEmpty(contact)) {
            binding.tilContactPerson.setError("Contact person required");
            valid = false;
        } else {
            binding.tilContactPerson.setError(null);
        }
        if (TextUtils.isEmpty(phone) || phone.length() < 10) {
            binding.tilPhone.setError("Valid phone required");
            valid = false;
        } else {
            binding.tilPhone.setError(null);
        }
        if (TextUtils.isEmpty(city)) {
            binding.tilCity.setError("City required");
            valid = false;
        } else {
            binding.tilCity.setError(null);
        }

        if (!valid) return;

        Customer c = new Customer(customerId, business, contact, phone, address, city);
        boolean ok = viewModel.saveCustomer(c);
        if (ok) {
            Snackbar.make(binding.getRoot(), "Customer saved", Snackbar.LENGTH_SHORT).show();
            finish();
        } else {
            Toast.makeText(this, "Save failed", Toast.LENGTH_SHORT).show();
        }
    }
}

