package com.hfad.agencyapp.ui.customers;

import android.content.Intent;
import android.os.Bundle;
import android.text.Editable;
import android.text.TextWatcher;
import android.view.MenuItem;
import android.view.View;
import android.widget.PopupMenu;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;
import androidx.recyclerview.widget.DividerItemDecoration;
import androidx.recyclerview.widget.LinearLayoutManager;

import com.google.android.material.dialog.MaterialAlertDialogBuilder;
import com.hfad.agencyapp.databinding.ActivityCustomersBinding;
import com.hfad.agencyapp.ui.adapters.CustomersAdapter;
import com.hfad.agencyapp.ui.models.Customer;
import com.hfad.agencyapp.viewmodel.CustomerViewModel;

/**
 * Activity that shows list of customers and allows add/edit/delete.
 */
public class CustomersActivity extends AppCompatActivity {
    private ActivityCustomersBinding binding;
    private CustomerViewModel viewModel;
    private CustomersAdapter adapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityCustomersBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        setSupportActionBar(binding.toolbar);
        getSupportActionBar().setDisplayHomeAsUpEnabled(true);
        binding.toolbar.setNavigationOnClickListener(v -> onBackPressed());

        viewModel = new ViewModelProvider(this).get(CustomerViewModel.class);

        setupRecyclerView();
        setupObservers();
        setupListeners();
    }

    private void setupRecyclerView() {
        adapter = new CustomersAdapter(new CustomersAdapter.OnCustomerActionListener() {
            @Override
            public void onClick(Customer customer) {
                // Open detail
                Intent intent = new Intent(CustomersActivity.this, CustomerDetailActivity.class);
                intent.putExtra("customer_id", customer.getId());
                startActivity(intent);
            }

            @Override
            public void onLongClick(Customer customer, View anchor) {
                showContextMenu(customer, anchor);
            }
        });
        binding.rvCustomers.setLayoutManager(new LinearLayoutManager(this));
        binding.rvCustomers.addItemDecoration(new DividerItemDecoration(this, DividerItemDecoration.VERTICAL));
        binding.rvCustomers.setAdapter(adapter);
    }

    private void setupObservers() {
        viewModel.getCustomers().observe(this, list -> {
            adapter.submitList(list);
            binding.emptyState.getRoot().setVisibility(list.isEmpty() ? View.VISIBLE : View.GONE);
        });
    }

    private void setupListeners() {
        binding.fabAddCustomer.setOnClickListener(v -> startActivity(new Intent(this, AddEditCustomerActivity.class)));

        binding.etSearch.addTextChangedListener(new TextWatcher() {
            private Runnable lastTask;
            @Override
            public void beforeTextChanged(CharSequence s, int start, int count, int after) {}

            @Override
            public void onTextChanged(CharSequence s, int start, int before, int count) {
                // Debounce 300ms
                binding.etSearch.removeCallbacks(lastTask);
                lastTask = () -> viewModel.filter(s.toString());
                binding.etSearch.postDelayed(lastTask, 300);
            }

            @Override
            public void afterTextChanged(Editable s) {}
        });
    }

    private void showContextMenu(Customer c, View anchor) {
        PopupMenu popup = new PopupMenu(this, anchor);
        popup.getMenu().add("Edit");
        popup.getMenu().add("Delete");
        popup.getMenu().add("Call");
        popup.setOnMenuItemClickListener(item -> {
            String title = item.getTitle().toString();
            if (title.equals("Edit")) {
                Intent intent = new Intent(CustomersActivity.this, AddEditCustomerActivity.class);
                intent.putExtra("customer_id", c.getId());
                startActivity(intent);
                return true;
            } else if (title.equals("Delete")) {
                new MaterialAlertDialogBuilder(this)
                        .setTitle("Delete Customer")
                        .setMessage("Are you sure you want to delete " + c.getBusinessName() + "?")
                        .setPositiveButton("Delete", (dialog, which) -> {
                            boolean ok = viewModel.deleteCustomer(c.getId());
                            Toast.makeText(this, ok ? "Deleted" : "Delete failed", Toast.LENGTH_SHORT).show();
                        })
                        .setNegativeButton("Cancel", null)
                        .show();
                return true;
            } else if (title.equals("Call")) {
                // dial
                Intent intent = new Intent(Intent.ACTION_DIAL);
                intent.setData(android.net.Uri.parse("tel:" + c.getPhoneNumber()));
                startActivity(intent);
                return true;
            }
            return false;
        });
        popup.show();
    }

    @Override
    public boolean onOptionsItemSelected(MenuItem item) {
        if (item.getItemId() == android.R.id.home) {
            onBackPressed();
            return true;
        }
        return super.onOptionsItemSelected(item);
    }
}

package com.hfad.agencyapp.ui.models;

/**
 * Data model for customer information.
 */
public class Customer {
    private String customerId;
    private String customerName;
    private String phoneNumber;
    private String address;

    public Customer(String customerId, String customerName, String phoneNumber, String address) {
        this.customerId = customerId;
        this.customerName = customerName;
        this.phoneNumber = phoneNumber;
        this.address = address;
    }

    // Getters & Setters
    public String getCustomerId() {
        return customerId;
    }

    public void setCustomerId(String customerId) {
        this.customerId = customerId;
    }

    public String getCustomerName() {
        return customerName;
    }

    public void setCustomerName(String customerName) {
        this.customerName = customerName;
    }

    public String getPhoneNumber() {
        return phoneNumber;
    }

    public void setPhoneNumber(String phoneNumber) {
        this.phoneNumber = phoneNumber;
    }

    public String getAddress() {
        return address;
    }

    public void setAddress(String address) {
        this.address = address;
    }
}

package com.hfad.agencyapp.ui.models;

/**
 * Data model for customer information used across the app.
 * Fields include minimal required details: id, business/shop name, contact person and city.
 */
public class Customer {
    private String id; // unique id (can be UUID or provider id)
    private String businessName;
    private String contactPerson;
    private String city;
    private String phoneNumber;
    private String address;

    public Customer() {
    }

    public Customer(String id, String businessName, String contactPerson, String phoneNumber, String address, String city) {
        this.id = id;
        this.businessName = businessName;
        this.contactPerson = contactPerson;
        this.phoneNumber = phoneNumber;
        this.address = address;
        this.city = city;
    }

    // Convenience constructor used earlier (legacy places)
    public Customer(String id, String name, String phone, String address) {
        this.id = id;
        this.businessName = name;
        this.contactPerson = "";
        this.phoneNumber = phone;
        this.address = address;
        this.city = "";
    }

    // Getters and setters
    public String getId() { return id; }
    public void setId(String id) { this.id = id; }

    public String getBusinessName() { return businessName; }
    public void setBusinessName(String businessName) { this.businessName = businessName; }

    public String getContactPerson() { return contactPerson; }
    public void setContactPerson(String contactPerson) { this.contactPerson = contactPerson; }

    public String getCity() { return city; }
    public void setCity(String city) { this.city = city; }

    public String getPhoneNumber() { return phoneNumber; }
    public void setPhoneNumber(String phoneNumber) { this.phoneNumber = phoneNumber; }

    public String getAddress() { return address; }
    public void setAddress(String address) { this.address = address; }
}

package com.hfad.agencyapp.viewmodel;

import android.app.Application;
import androidx.annotation.NonNull;
import androidx.lifecycle.AndroidViewModel;
import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;

import com.hfad.agencyapp.data.CustomerRepository;
import com.hfad.agencyapp.ui.models.Customer;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.Future;

/**
 * ViewModel for managing customers list and CRUD operations.
 */
public class CustomerViewModel extends AndroidViewModel {
    private final CustomerRepository repository;
    private final MutableLiveData<List<Customer>> customers = new MutableLiveData<>(new ArrayList<>());
    private final MutableLiveData<Boolean> loading = new MutableLiveData<>(false);
    private final MutableLiveData<String> error = new MutableLiveData<>(null);

    public CustomerViewModel(@NonNull Application application) {
        super(application);
        repository = new CustomerRepository(application);
        loadAll();
    }

    public LiveData<List<Customer>> getCustomers() { return customers; }
    public LiveData<Boolean> getLoading() { return loading; }
    public LiveData<String> getError() { return error; }

    public void loadAll() {
        loading.postValue(true);
        Future<List<Customer>> f = repository.getAllCustomersAsync();
        try {
            List<Customer> list = f.get();
            customers.postValue(list);
        } catch (ExecutionException | InterruptedException e) {
            error.postValue(e.getMessage());
        } finally {
            loading.postValue(false);
        }
    }

    public void filter(String q) {
        if (q == null || q.trim().isEmpty()) {
            loadAll();
            return;
        }
        loading.postValue(true);
        Future<List<Customer>> f = repository.searchCustomersAsync(q);
        try {
            List<Customer> list = f.get();
            customers.postValue(list);
        } catch (ExecutionException | InterruptedException e) {
            error.postValue(e.getMessage());
        } finally {
            loading.postValue(false);
        }
    }

    public boolean saveCustomer(Customer c) {
        try {
            Future<String> f = repository.insertOrUpdateAsync(c);
            String id = f.get();
            if (id != null) {
                loadAll();
                return true;
            }
        } catch (ExecutionException | InterruptedException e) {
            error.postValue(e.getMessage());
        }
        return false;
    }

    public boolean deleteCustomer(String id) {
        try {
            Future<Boolean> f = repository.deleteCustomerAsync(id);
            boolean ok = f.get();
            if (ok) loadAll();
            return ok;
        } catch (ExecutionException | InterruptedException e) {
            error.postValue(e.getMessage());
            return false;
        }
    }

    public Customer getById(String id) {
        try {
            Future<Customer> f = repository.getByIdAsync(id);
            return f.get();
        } catch (ExecutionException | InterruptedException e) {
            error.postValue(e.getMessage());
            return null;
        }
    }
}
